import React, { useState, useEffect, useRef } from 'react';
import {
  Paper,
  Typography,
  Box,
  Skeleton,
  useTheme,
  Divider,
  TextField,
  Button,
  Grid,
  Card,
  CardContent,
  Collapse,
  IconButton
} from '@mui/material';
import {
  ShowChart,
  Timeline,
  TrendingUp,
  FilterList,
  ExpandMore,
  ExpandLess
} from '@mui/icons-material';
import dashboardService from '../../services/dashboardService';
import logger from '../../utils/logger';
import { formatCurrency, formatPercentage, getColorByValue } from '../../utils/formatters';

const ConsolidatedStatsCard = ({ hideValues = false }) => {
  const theme = useTheme();
  const [stats, setStats] = useState({
    realized_pnl: 0,
    unrealized_pnl: 0,
    total_pnl: 0,
    win_rate: 0,
    total_trades: 0,
    winning_trades: 0,
    open_positions_count: 0,
  });

  const [loading, setLoading] = useState(true);
  const [initialLoad, setInitialLoad] = useState(true);
  const [error, setError] = useState('');
  const [lastUpdated, setLastUpdated] = useState(new Date());
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [filterDates, setFilterDates] = useState({ startDate: '', endDate: '' });

  // Referência para o timer de 30 segundos
  const intervalRef = useRef(null);

  // Carregar dados do dashboard
  useEffect(() => {
    const loadStats = async (showLoading = true) => {
      try {
        if (showLoading && initialLoad) {
          setLoading(true);
        }
        const [statsResponse, openPositionsResponse, closedTradesResponse] = await Promise.all([
          dashboardService.getUserStats(filterDates.startDate, filterDates.endDate),
          dashboardService.getOpenPositions(),
          dashboardService.getClosedTrades()
        ]);

        const statsData = statsResponse.data || statsResponse;
        const openPositionsData = openPositionsResponse.data || [];
        const closedTradesData = closedTradesResponse.data || [];

        setStats(statsData);

        // Marcar que o carregamento inicial foi concluído
        if (initialLoad) {
          setInitialLoad(false);
        }
      } catch (error) {
        console.error('Erro ao carregar estatísticas:', error);
        setStats({
          realized_pnl: 0,
          unrealized_pnl: 0,
          total_pnl: 0,
          win_rate: 0,
          total_trades: 0,
          winning_trades: 0,
          open_positions_count: 0,
        });
      } finally {
        if (showLoading && initialLoad) {
          setLoading(false);
        }
      }
    };

    // Carregar dados (com ou sem loading dependendo se é inicial ou filtro)
    loadStats(initialLoad);

    // Timer para atualização automática a cada 30 segundos (sem loading)
    const interval = setInterval(() => {
      if (!initialLoad) { // Só inicia o timer após carregamento inicial
        loadStats(false);
      }
    }, 30000);

    return () => clearInterval(interval);
  }, [filterDates.startDate, filterDates.endDate, initialLoad]); // Incluindo as dependências de volta

  // Função para limpar filtros
  const clearFilters = () => {
    setFilterDates({ startDate: '', endDate: '' });
  };

  // Funções de formatação agora são importadas de utils/formatters.js para garantir consistência

  // Usar dados das estatísticas do backend (que já calculam baseado na Bitget)
  const getRealizedProfit = () => {
    // Usar dados do backend que busca da Bitget
    return stats?.realized_pnl || 0;
  };

  // Usar taxa de acerto das estatísticas do backend
  const getWinRate = () => {
    // Usar dados do backend que calcula baseado na Bitget
    return stats?.win_rate || 0;
  };

  // Calcular ROE das posições abertas
  const calculateOpenROE = () => {
    const unrealizedPnl = parseFloat(stats?.unrealized_pnl || 0);
    const marginSize = parseFloat(stats?.margin_size || 0);

    // Evitar divisão por zero se não houver margem
    if (marginSize === 0) {
      return 0;
    }

    const roe = (unrealizedPnl / marginSize) * 100;
    return roe;
  };

  const realizedProfit = getRealizedProfit();
  const winRate = getWinRate();
  const openROE = calculateOpenROE();

  // Debug: verificar dados carregados
  console.log('Stats from backend:', stats);
  console.log('Realized profit from stats:', realizedProfit);
  console.log('Win rate from stats:', winRate);

  if (loading) {
    return (
      <Paper sx={{ p: 2.5, height: 320 }}>
        <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 2, fontSize: '1.1rem' }}>
          📊 Estatísticas de Trading
        </Typography>
        <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
          <Skeleton variant="rectangular" height={60} />
          <Skeleton variant="rectangular" height={60} />
          <Skeleton variant="rectangular" height={60} />
        </Box>
      </Paper>
    );
  }

  return (
    <Paper sx={{ p: 2.5, height: 'auto', minHeight: 320, transition: 'all 0.3s ease-in-out' }}>
      {/* Cabeçalho */}
      <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 2 }}>
        <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1, fontSize: '1.1rem' }}>
          📊 Estatísticas de Trading
        </Typography>
        <IconButton 
          onClick={() => setIsFilterOpen(!isFilterOpen)}
          size="small"
          sx={{ color: theme.palette.primary.main }}
        >
          <FilterList />
          {isFilterOpen ? <ExpandLess /> : <ExpandMore />}
        </IconButton>
      </Box>

      {/* Filtros de Data */}
      <Collapse in={isFilterOpen}>
        <Card sx={{ mb: 2, bgcolor: 'background.default' }}>
          <CardContent sx={{ p: 1.5, '&:last-child': { pb: 1.5 } }}>
            <Grid container spacing={1.5}>
              <Grid item xs={12} md={4}>
                <TextField
                  label="Data Inicial"
                  type="date"
                  value={filterDates.startDate}
                  onChange={(e) => setFilterDates({ ...filterDates, startDate: e.target.value })}
                  InputLabelProps={{
                    shrink: true,
                  }}
                  fullWidth
                  size="small"
                />
              </Grid>
              <Grid item xs={12} md={4}>
                <TextField
                  label="Data Final"
                  type="date"
                  value={filterDates.endDate}
                  onChange={(e) => setFilterDates({ ...filterDates, endDate: e.target.value })}
                  InputLabelProps={{
                    shrink: true,
                  }}
                  fullWidth
                  size="small"
                />
              </Grid>
              <Grid item xs={12} md={4}>
                <Button
                  variant="outlined"
                  onClick={clearFilters}
                  fullWidth
                  size="small"
                >
                  Limpar Filtros
                </Button>
              </Grid>
            </Grid>
            <Typography variant="caption" sx={{ color: 'text.secondary', mt: 1, display: 'block' }}>
              * Sem filtro = mês atual. Com filtro = período personalizado para o Lucro Realizado.
            </Typography>
          </CardContent>
        </Card>
      </Collapse>

      {/* Conteúdo */}
      <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>

        {/* Lucro Realizado */}
        <Box sx={{ 
          display: 'flex', 
          alignItems: 'center', 
          justifyContent: 'space-between',
          p: 1.5,
          bgcolor: 'background.default',
          borderRadius: 1,
          border: `1px solid ${theme.palette.divider}`
        }}>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
            <Timeline sx={{ color: getColorByValue(realizedProfit), fontSize: 20 }} />
            <Typography variant="body1" sx={{ fontWeight: 500 }}>
              Lucro Realizado
            </Typography>
          </Box>
          <Typography 
            variant="h6" 
            sx={{ 
              fontWeight: 'bold',
              color: getColorByValue(realizedProfit)
            }}
          >
            {realizedProfit >= 0 ? '+' : ''}{formatCurrency(realizedProfit, true, hideValues)}
          </Typography>
        </Box>

        <Divider sx={{ my: 0.5 }} />

        {/* ROE Aberto */}
        <Box sx={{ 
          display: 'flex', 
          alignItems: 'center', 
          justifyContent: 'space-between',
          p: 1.5,
          bgcolor: 'background.default',
          borderRadius: 1,
          border: `1px solid ${theme.palette.divider}`
        }}>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
            <ShowChart sx={{ color: getColorByValue(openROE || 0), fontSize: 20 }} />
            <Typography variant="body1" sx={{ fontWeight: 500 }}>
              ROE Aberto =
            </Typography>
          </Box>
          <Typography 
            variant="h6" 
            sx={{ 
              fontWeight: 'bold',
              color: getColorByValue(openROE || 0)
            }}
          >
            {formatPercentage(openROE, false)}
          </Typography>
        </Box>

        <Divider sx={{ my: 0.5 }} />

        {/* Taxa de Acerto */}
        <Box sx={{ 
          display: 'flex', 
          alignItems: 'center', 
          justifyContent: 'space-between',
          p: 1.5,
          bgcolor: 'background.default',
          borderRadius: 1,
          border: `1px solid ${theme.palette.divider}`
        }}>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
            <TrendingUp sx={{ color: getColorByValue(winRate), fontSize: 20 }} />
            <Typography variant="body1" sx={{ fontWeight: 500 }}>
              Taxa de Acerto
            </Typography>
          </Box>
          <Typography 
            variant="h6" 
            sx={{ 
              fontWeight: 'bold',
              color: getColorByValue(winRate)
            }}
          >
            {formatPercentage(winRate, false)}
          </Typography>
        </Box>

        {/* Informação adicional */}
        <Box sx={{ mt: 'auto', pt: 1 }}>
          <Typography variant="caption" color="text.secondary" align="center" display="block">
            Atualizado automaticamente a cada 30 segundos
          </Typography>
        </Box>
      </Box>
    </Paper>
  );
};

export default ConsolidatedStatsCard;
